        d['?' ] = &.{31, 32, 60};
        d['A' ] = &.{64};
        d['B' ] = &.{64};
        d['C' ] = &.{64};
        d['D' ] = &.{64};
        d['E' ] = &.{64};
        d['F' ] = &.{64};
        d['G' ] = &.{64};
        d['H' ] = &.{64};
        d['I' ] = &.{64};
        d['J' ] = &.{64};
        d['K' ] = &.{64};
        d['L' ] = &.{64};
        d['M' ] = &.{64};
        d['N' ] = &.{64};
        d['O' ] = &.{64};
        d['P' ] = &.{64};
        d['Q' ] = &.{64};
        d['R' ] = &.{64};
        d['S' ] = &.{64};
        d['T' ] = &.{64};
        d['U' ] = &.{64};
        d['V' ] = &.{64};
        d['W' ] = &.{64};
        d['X' ] = &.{64};
        d['Y' ] = &.{64};
        d['Z' ] = &.{64};
        d['[' ] = &.{58};
        d['\\'] = &.{1, 62};
        d[']' ] = &.{59};
        d['_' ] = &.{64};
        d['`' ] = &.{9, 10};
        d['a' ] = &.{64};
        d['b' ] = &.{64};
        d['c' ] = &.{64};
        d['d' ] = &.{64};
        d['e' ] = &.{64};
        d['f' ] = &.{64};
        d['g' ] = &.{64};
        d['h' ] = &.{64};
        d['i' ] = &.{64};
        d['j' ] = &.{64};
        d['k' ] = &.{64};
        d['l' ] = &.{64};
        d['m' ] = &.{64};
        d['n' ] = &.{64};
        d['o' ] = &.{64};
        d['p' ] = &.{64};
        d['q' ] = &.{64};
        d['r' ] = &.{64};
        d['s' ] = &.{64};
        d['t' ] = &.{64};
        d['u' ] = &.{64};
        d['v' ] = &.{64};
        d['w' ] = &.{64};
        d['x' ] = &.{64};
        d['y' ] = &.{64};
        d['z' ] = &.{64};
        d['{' ] = &.{56};
        d['|' ] = &.{21, 23, 42};
        d['}' ] = &.{57};
        d['~' ] = &.{65};
        break :blk d;
    };

    var compiled: [67]?regex.Regex = .{null} ** 67;
    var initialized: bool = false;

    fn ensureInit() void {
        if (initialized) return;
        regex.init();
        for (rules, 0..) |rule, i| {
            compiled[i] = regex.Regex.compile(rule.pat) catch null;
        }
        initialized = true;
    }

    fn matchRules(self: *Lexer) Token {
        ensureInit();
        while (true) {
            const ws_start = self.pos;
            while (self.pos < self.source.len and (self.source[self.pos] == ' ' or self.source[self.pos] == '\t'))
                self.pos += 1;
            const ws_count: u8 = @intCast(@min(self.pos - ws_start, 255));

            if (self.pos >= self.source.len)
                return Token{ .cat = .eof, .pre = ws_count, .pos = @intCast(self.pos), .len = 0 };

            // Check for standalone regex: ~<delim> where delim is not / or alnum
            if (self.pos + 1 < self.source.len and self.source[self.pos] == '~') {
                const rd = self.source[self.pos + 1];
                if (rd != '/' and !std.ascii.isAlphanumeric(rd) and rd != ' ' and rd != '\t' and rd != '\n' and rd != '\r' and rd != '_') {
                    var result = self.collectRegex();
                    result.pre = ws_count;
                    self.last_cat = result.cat;
                    return result;
                }
            }

            const start: u32 = @intCast(self.pos);
            self.beg = 0;
            var best_len: usize = 0;
            var best_rule: usize = 67;
            for (dispatch[self.source[self.pos]]) |ri| {
                if (compiled[ri]) |re| {
                    if (re.matchAt(self.source, self.pos)) |len| {
                        if (len > best_len) {
                            best_len = len;
                            best_rule = ri;
                        }
                    }
                }
            }

            if (best_rule < 67) {
                self.pos += @intCast(best_len);
                const rule = rules[best_rule];

                for (rule.acts) |act| {
                    const states = [_]*i32{&self.beg, &self.heredoc, &self.paren, &self.brace};
                    switch (act.k) {
                        .set => states[act.v].* = act.n,
                        .inc => states[act.v].* += 1,
                        .dec => states[act.v].* -= 1,
                    }
                }

                if (rule.skip) continue;

                const final_cat = if (rule.tok == .lparen and ws_count == 0) .lparen_tight else rule.tok;
                return Token{ .cat = final_cat, .pre = ws_count, .pos = start, .len = @intCast(best_len) };
            }

            self.pos += 1;
            return Token{ .cat = .err, .pre = ws_count, .pos = start, .len = 1 };
        }
    }
};

