    pub fn parseProgram(self: *Parser) !Sexp {
        self.injected_token = SYM_program_START;
        return self.doParse(SYM_program);
    }
    pub fn parseOneline(self: *Parser) !Sexp {
        self.injected_token = SYM_oneline_START;
        return self.doParse(SYM_oneline);
    }
};

// Symbol IDs
const SYM_program: u16 = 4;
const SYM_program_START: u16 = 140;
const SYM_oneline: u16 = 5;
const SYM_oneline_START: u16 = 142;
const SYM_IDENT: u16 = 44;

// Mapping from if_id to grammar symbol IDs (computed at comptime)
const if_to_symbol = blk: {
    var arr: [512]u16 = .{0} ** 512;
    for (@typeInfo(if_id).@"enum".fields) |field| {
        if (arr[field.value] == 0) arr[field.value] = 100;
    }
    break :blk arr;
};

